import{p as n}from"./chunks/presentationSlides.D90XTQsY.js";import{_ as o,C as r,c as s,o as i,a5 as t,G as d,k as l}from"./chunks/framework.CgT1UzWm.js";const v=JSON.parse('{"title":"The Backend That Writes Itself — NpgsqlRest in 19 Slides","titleTemplate":"NpgsqlRest","description":"An interactive slide deck: how NpgsqlRest turns a PostgreSQL database into a complete, production-grade backend — REST API, typed TypeScript client, and AI-agent tools — with real, reproducible numbers from a product in production.","frontmatter":{"layout":"doc","outline":[2,3],"title":"The Backend That Writes Itself — NpgsqlRest in 19 Slides","titleTemplate":"NpgsqlRest","description":"An interactive slide deck: how NpgsqlRest turns a PostgreSQL database into a complete, production-grade backend — REST API, typed TypeScript client, and AI-agent tools — with real, reproducible numbers from a product in production.","head":[["meta",{"name":"keywords","content":"npgsqlrest presentation, postgresql backend, sql rest api, declarative backend, ai infrastructure postgres, postgrest supabase alternative"}],["meta",{"property":"og:title","content":"The Backend That Writes Itself — NpgsqlRest in 19 Slides"}],["meta",{"property":"og:description","content":"An interactive slide deck on turning PostgreSQL into a complete production backend with NpgsqlRest."}],["meta",{"property":"og:type","content":"article"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/presentation/slide-1.png"}]]},"headers":[],"relativePath":"blog/the-backend-that-writes-itself-presentation.md","filePath":"blog/the-backend-that-writes-itself-presentation.md"}'),h={name:"blog/the-backend-that-writes-itself-presentation.md"},c=Object.assign(h,{setup(g){return(p,e)=>{const a=r("SlideDeck");return i(),s("div",null,[e[0]||(e[0]=t('<h1 id="the-backend-that-writes-itself" tabindex="-1" data-v-ae37f820>The Backend That Writes Itself <a class="header-anchor" href="#the-backend-that-writes-itself" aria-label="Permalink to &quot;The Backend That Writes Itself&quot;" data-v-ae37f820>​</a></h1><p data-v-ae37f820><em data-v-ae37f820>An interactive walk-through of the NpgsqlRest pitch deck — point a single binary at PostgreSQL and get a complete, production-grade backend: a REST API, a typed TypeScript client, and AI-agent tools, all generated from your schema.</em></p><p data-v-ae37f820>Use the arrows, thumbnails, or your keyboard (<strong data-v-ae37f820>←/→</strong> to move, <strong data-v-ae37f820>F</strong> for fullscreen, <strong data-v-ae37f820>N</strong> for speaker notes). Hit <strong data-v-ae37f820>▶</strong> to let it auto-advance. Every figure in the deck is measured from a real product in production and is reproducible — see the appendix slides.</p>',3)),d(a,{slides:l(n),title:"The backend that writes itself · 2026"},null,8,["slides"]),e[1]||(e[1]=t('<h2 id="the-narration" tabindex="-1" data-v-ae37f820>The narration <a class="header-anchor" href="#the-narration" aria-label="Permalink to &quot;The narration&quot;" data-v-ae37f820>​</a></h2><p data-v-ae37f820>The deck is designed to be skimmed visually, but the story is in the speaker notes. Here it is slide by slide.</p><div class="transcript" data-v-ae37f820><ol data-v-ae37f820><li data-v-ae37f820><strong data-v-ae37f820>The backend that writes itself.</strong> I built a tool that turns a Postgres database into a complete, production-grade backend — and I&#39;ve been running a real product on it for 9 months.</li><li data-v-ae37f820><strong data-v-ae37f820>The tax.</strong> Change one column and you touch five files in three languages. Every team on earth pays this tax. It has nothing to do with their product.</li><li data-v-ae37f820><strong data-v-ae37f820>The solution.</strong> A single native binary. You point it at your database, it builds the API at startup, and writes the typed frontend client into your source tree. The contract can&#39;t drift — it&#39;s generated from the schema minutes ago.</li><li data-v-ae37f820><strong data-v-ae37f820>An endpoint is a SQL file.</strong> The same endpoint in a traditional stack is route, controller, validation, DTO, service, repository, client type, client function — 5 to 7 files, 2 to 3 languages, plus a code review for each. Here, an endpoint is a SQL file.</li><li data-v-ae37f820><strong data-v-ae37f820>The type-system collapse.</strong> One source of truth. In the case-study product, 154 API contracts exist — and exactly zero are maintained by a human.</li><li data-v-ae37f820><strong data-v-ae37f820>The declarative holy grail.</strong> You state intent and the machine guarantees execution. Everyone who chased it built a new language and died on the adoption curve. We didn&#39;t invent a language — we removed everything except the declarative language that won 50 years ago. Declaring intent is exactly what AI models are best at.</li><li data-v-ae37f820><strong data-v-ae37f820>Not a demo. A product.</strong> Every number here is measured from the repo and reproducible. The backend of this product is PostgreSQL plus one JSON file.</li><li data-v-ae37f820><strong data-v-ae37f820>Making change cheap.</strong> The origin story is requirements churn — stakeholders who only recognize what they want when they see it working. The only winning strategy is making change cheap. The generated client files changed 108 times: 108 rounds of &quot;they changed their mind,&quot; absorbed automatically.</li><li data-v-ae37f820><strong data-v-ae37f820>Declarative everything.</strong> Security, caching, real-time — the checklist every business app needs — is declarative. You can audit the security posture of the whole API with <code data-v-ae37f820>grep</code>.</li><li data-v-ae37f820><strong data-v-ae37f820>Performance.</strong> The usual trade is convenience vs. performance. Here the convenient thing is also the fast thing, because we removed the layers instead of optimizing them. Note what we&#39;re compared against: hand-tuned raw-driver code no real team ships. Real projects use ORMs — the EF Core row is 30% slower.</li><li data-v-ae37f820><strong data-v-ae37f820>vs. PostgREST &amp; Supabase.</strong> They validated the category. We differ on who writes the query: they let the client specify it, capping you at their URL syntax and exposing your whole schema. We say write SQL — the most expressive data language ever made — and expose exactly that. Plus we&#39;re 2.6× faster and one binary instead of seven services.</li><li data-v-ae37f820><strong data-v-ae37f820>Enterprise features.</strong> The unglamorous things enterprise deals hang on: upload an Excel file, encrypt SSNs, route reads to replicas. Each is normally a sprint; here each is an annotation.</li><li data-v-ae37f820><strong data-v-ae37f820>The worst case.</strong> We measured the worst case for this architecture and still got 28%. The average business app does better, because the average business app is mostly the plumbing we delete.</li><li data-v-ae37f820><strong data-v-ae37f820>We removed the glue code.</strong> Everyone is making AI write the glue code faster. We removed the glue code. The agent reads two files, declares intent in SQL, and machines verify the rest. A third of commits are AI-co-authored, with a human owning design and review.</li><li data-v-ae37f820><strong data-v-ae37f820>Agents touching your data safely.</strong> The same governed, role-checked, rate-limited endpoints you already have — one annotation away. The database becomes the single source of truth for apps, frontends, <em data-v-ae37f820>and</em> agents. It&#39;s still the same file.</li><li data-v-ae37f820><strong data-v-ae37f820>An AI-infrastructure play.</strong> Five years ago this would have been a developer-productivity tool. Today it&#39;s the architecture that makes both AI-written code and AI-called APIs cheap and safe.</li><li data-v-ae37f820><strong data-v-ae37f820>The loop.</strong> We measured what this did for one product — a third of the code never written, one developer doing a team&#39;s work. Now multiply that across every product we build, and every AI agent that will want to talk to them.</li><li data-v-ae37f820><strong data-v-ae37f820>Appendix A1.</strong> Every measured value is from the production repo and reproducible — exact commands in the case-study raw-data appendix.</li><li data-v-ae37f820><strong data-v-ae37f820>Appendix A2.</strong> The full feature list. The message is the <em data-v-ae37f820>length</em> of the list, and that each line is an annotation or a config block — not a sprint.</li></ol></div><h2 id="where-to-go-next" tabindex="-1" data-v-ae37f820>Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;" data-v-ae37f820>​</a></h2><ul data-v-ae37f820><li data-v-ae37f820><a href="/blog/case-study-zero-backend-code.html" data-v-ae37f820>Case Study: 74 Endpoints, Zero Backend Code</a> — the production product behind these numbers.</li><li data-v-ae37f820><a href="/blog/sql-rest-api.html" data-v-ae37f820>SQL REST API</a> — the philosophy in long form, in the author&#39;s own words.</li><li data-v-ae37f820><a href="/blog/npgsqlrest-vs-postgrest-supabase-comparison.html" data-v-ae37f820>NpgsqlRest vs PostgREST vs Supabase</a> — the category comparison from slide 11.</li><li data-v-ae37f820><a href="/blog/mcp-server-postgresql-ai-tools-npgsqlrest.html" data-v-ae37f820>Turn PostgreSQL into MCP Tools an AI Agent Can Call</a> — the AI-agent story from slides 14–16.</li></ul>',5))])}}}),m=o(c,[["__scopeId","data-v-ae37f820"]]);export{v as __pageData,m as default};
